import play.api.mvc._
import slick.jdbc.MySQLProfile.api._
import scala.concurrent.Future

class ProductSearchController @Inject()(val db: Database) extends Controller {

  def searchProducts = Action.async { implicit request =>
    val searchParams = request.queryString
    val whereClause = searchParams.map { case (key, values) => s"${key} IN ('${values.mkString("', '")}')" }.mkString(" AND ")
    val products = db.run(sql"SELECT * FROM products WHERE ${sqlFragment(whereClause)}".as[Product])
    products.map(Ok(_))
  }
